package co.edu.elecciones.controller; import co.edu.elecciones.commons.dto.ApiResponse; import co.edu.elecciones.domain.*; import co.edu.elecciones.dto.Requests; import co.edu.elecciones.repository.*; import co.edu.elecciones.service.AuditService; import jakarta.servlet.http.HttpServletRequest; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/v1/usuarios") public class UsuariosController { private final UserRepository repo; private final AuditService audit; private final org.springframework.security.crypto.password.PasswordEncoder passwordEncoder; public UsuariosController(UserRepository repo, AuditService audit , org.springframework.security.crypto.password.PasswordEncoder passwordEncoder){this.repo=repo;this.audit=audit; this.passwordEncoder=passwordEncoder;}
 @GetMapping public ApiResponse<List<AppUser>> all(){return ApiResponse.ok("OK",repo.findAll());}
 @GetMapping("/{id}") public ApiResponse<AppUser> one(@PathVariable Long id){return ApiResponse.ok("OK",repo.findById(id).orElseThrow());}
 @PostMapping public ApiResponse<AppUser> create(@RequestBody Requests.UserRequest req, HttpServletRequest http){ AppUser u=new AppUser(); u.name=req.name(); u.email=req.email(); if(req.password()!=null&&!req.password().isBlank()) u.password=passwordEncoder.encode(req.password()); u.role=req.role(); if(req.active()!=null) u.active=req.active(); var saved=repo.save(u); audit.log("CREATE","AppUser",saved.id,"Creación",http); return ApiResponse.ok("Creado",saved);}
 @PutMapping("/{id}") public ApiResponse<AppUser> update(@PathVariable Long id,@RequestBody Requests.UserRequest req,HttpServletRequest http){ var u=repo.findById(id).orElseThrow(); u.name=req.name(); u.email=req.email(); if(req.password()!=null&&!req.password().isBlank()) u.password=passwordEncoder.encode(req.password()); u.role=req.role(); if(req.active()!=null) u.active=req.active(); var saved=repo.save(u); audit.log("UPDATE","AppUser",saved.id,"Actualización",http); return ApiResponse.ok("Actualizado",saved);}
 @DeleteMapping("/{id}") public ApiResponse<Void> delete(@PathVariable Long id,HttpServletRequest http){repo.deleteById(id); audit.log("DELETE","AppUser",id,"Eliminación",http); return ApiResponse.ok("Eliminado",null);}
}
